import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o,c as t,a as e,b as a,e as d,d as r}from"./app-8955ab6e.js";const c="/assets/15-20230617203109-igukewd-20230730160958-dmy759d-9b614581.png",l="/assets/16-20230617203109-n7f7p12-20230730161012-02mgopr-8ecb3e69.png",u="/assets/17-20230617203109-8up3h6b-20230730161032-p253go4-d2699fea.png",p="/assets/18-20230617203109-gxjgrfm-20230730161032-iyjm02s-e1084062.png",m="/assets/24-20230617203109-ce0umeg-20230730161303-56zjoru-d3ac545a.png",h="/assets/25-20230617203109-3itur2i-20230730161318-y8mwzb7-4507ad6e.png",v={},b=r('<h1 id="docker安装" tabindex="-1"><a class="header-anchor" href="#docker安装" aria-hidden="true">#</a> Docker安装</h1><h3 id="docker的基本组成" tabindex="-1"><a class="header-anchor" href="#docker的基本组成" aria-hidden="true">#</a> Docker的基本组成</h3><h4 id="镜像-image" tabindex="-1"><a class="header-anchor" href="#镜像-image" aria-hidden="true">#</a> 镜像（image）</h4><p>Docker 镜像（Image）就是一个 <strong>只读</strong> 的模板。镜像可以用来创建 Docker 容器， 一个镜像可以创建很多容器 。</p><p>它也相当于是一个root文件系统。比如官方镜像 centos:7 就包含了完整的一套 centos:7 最小系统的 root 文件系统。</p><p>相当于容器的“源代码”， docker镜像文件类似于Java的类模板，而docker容器实例类似于由类new出来的实例对象。</p><h4 id="容器-container" tabindex="-1"><a class="header-anchor" href="#容器-container" aria-hidden="true">#</a> 容器（container）</h4><ul><li><strong>从面向对象角度</strong></li></ul><p>Docker 利用容器（Container）独立运行的一个或一组应用，应用程序或服务运行在容器里面；容器就类似于一个虚拟化的运行环境， 容器是用镜像创建的运行实例 。</p><p>就像是Python中的类和实例对象一样，镜像是静态的定义，容器是镜像运行时的实体。</p><p>容器为镜像提供了一个标准的和隔离的运行环境 ，它可以被启动、开始、停止、删除。</p><p>每个容器都是相互隔离的、保证安全的平台</p><ul><li><strong>从镜像容器角度</strong></li></ul><p><strong>可以把容器看做是一个简易版的</strong> <strong>Linux</strong> <strong>环境</strong> （包括root用户权限、进程空间、用户空间和网络空间等）和运行在其中的应用程序。</p><h4 id="仓库-repository" tabindex="-1"><a class="header-anchor" href="#仓库-repository" aria-hidden="true">#</a> 仓库（repository）</h4><p>仓库（Repository）是 集中存放镜像 文件的场所；类似于github仓库，存放各种git项目的地方。</p><p>Docker公司提供的官方<code>registry</code>​被称为Docker Hub，存放各种镜像模板的地方。</p><p>仓库分为公开仓库（Public）和私有仓库（Private）两种形式。</p>',18),g={href:"https://hub.docker.com/",target:"_blank",rel:"noopener noreferrer"},k=r('<p>国内的公开仓库包括阿里云 、网易云等</p><h4 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h4><blockquote><p><strong>需要正确的理解仓库/镜像/容器这几个概念:</strong></p></blockquote><p>Docker 本身是一个容器运行载体或称之为管理引擎。</p><p>把应用程序和配置依赖打包好形成一个可交付的运行环境，这个打包好的运行环境就是image镜像文件。​</p><p>只有通过这个镜像文件才能生成Docker容器实例(类似由类new出来一个对象)。</p><p>image文件可以看作是容器的模板。Docker 根据 image 文件生成容器的实例。同一个 image 文件，可以生成多个同时运行的容器实例。</p><blockquote><p><strong>镜像文件</strong></p></blockquote><p>image 文件生成的容器实例，本身也是一个文件，称为镜像文件。</p><blockquote><p><strong>容器实例</strong></p></blockquote><p>一个容器运行一种服务，当我们需要的时候，就可以通过docker客户端创建一个对应的运行实例，也就是我们的容器 。</p><blockquote><p><strong>仓库</strong></p></blockquote><p>就是放一堆镜像的地方，我们可以把镜像发布到仓库中，需要的时候再从仓库中拉下来就可以了。</p><h3 id="docker平台架构图解-入门版" tabindex="-1"><a class="header-anchor" href="#docker平台架构图解-入门版" aria-hidden="true">#</a> Docker平台架构图解（入门版）</h3><p>​​<img src="'+c+'" alt="15-20230617203109-igukewd" loading="lazy">​​</p><h4 id="docker工作原理" tabindex="-1"><a class="header-anchor" href="#docker工作原理" aria-hidden="true">#</a> Docker工作原理</h4><p>Docker是一个Client-Server结构的系统，Docker守护进程运行在主机上， 然后通过Socket连接从客户端访问，守护进程从客户端接受命令并管理运行在主机上的容器 。</p><p>容器，是一个运行时环境，就是我们前面说到的集装箱。</p><p>​<img src="'+l+'" alt="16-20230617203109-n7f7p12" loading="lazy">​</p><h4 id="整体架构及底层通信原理简述" tabindex="-1"><a class="header-anchor" href="#整体架构及底层通信原理简述" aria-hidden="true">#</a> 整体架构及底层通信原理简述</h4><p>Docker是一个C/S模式的架构，后端是一个松耦合架构，众多模块各司其职</p><h4 id="docker运行的基本流程为" tabindex="-1"><a class="header-anchor" href="#docker运行的基本流程为" aria-hidden="true">#</a> Docker运行的基本流程为：</h4><ol><li>​用户是使用Docker Client 与Docker Daemon 建立通信，并发送请求给后者。​</li><li>Docker Daemon 作为Docker架构中的主体部分，首先提供Docker Server 的功能时期可以接受 Docker Client的请求。</li><li>Docker Engine 执行Docker内部的一些列工作，每一项工作都是以一个Job的形式的存在。</li><li>Job的运行过程中，当需要容器镜像是，则从Docker Register中下载镜像，并通过镜像管理驱动Graph driver 将下载镜像以Graph的形式存储。</li><li>当需要为Docker创建网络环境时，通过网络驱动Network driver创建并配置Docker容器网络环境。</li><li>当需要限制Docker容器运行资源或执行用户指令等操作时，则通过Exec driver来完成。</li><li>Libcontainer是一项独立的容器管理包，Network driver以及Exec driver都是通过Libcontainer来实现具体容器进行的操作。</li></ol><p>​<img src="'+u+'" alt="17-20230617203109-8up3h6b" loading="lazy">​</p><p>​<img src="'+p+`" alt="18-20230617203109-gxjgrfm" loading="lazy">​</p><p>‍</p><h3 id="安装步骤" tabindex="-1"><a class="header-anchor" href="#安装步骤" aria-hidden="true">#</a> 安装步骤</h3><h4 id="fedora-centos-rhel" tabindex="-1"><a class="header-anchor" href="#fedora-centos-rhel" aria-hidden="true">#</a> Fedora/CentOS/RHEL</h4><p>1、若您安装过docker，需要先删掉，之后再安装依赖:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo yum remove docker docker-common docker-selinux docker-engine
sudo yum install -y yum-utils device-mapper-persistent-data lvm2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>2、根据版本不同，下载repo文件。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># CentOS/RHEL 
wget -O /etc/yum.repos.d/docker-ce.repo https://repo.huaweicloud.com/docker-ce/linux/centos/docker-ce.repo
# Fedora
wget -O /etc/yum.repos.d/docker-ce.repo https://repo.huaweicloud.com/docker-ce/linux/fedora/docker-ce.repo
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>软件仓库地址替换为：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># CentOS/RHEL 
sudo sed -i &#39;s+download.docker.com+repo.huaweicloud.com/docker-ce+&#39; /etc/yum.repos.d/docker-ce.repo
# Fedora
sudo sed -i &#39;s+download.docker.com+repo.huaweicloud.com/docker-ce+&#39; /etc/yum.repos.d/docker-ce.repo
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>3、更新索引文件并安装</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo yum makecache fast
sudo yum install docker-ce
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="debian-ubuntu" tabindex="-1"><a class="header-anchor" href="#debian-ubuntu" aria-hidden="true">#</a> Debian/Ubuntu</h4><p>1、若您安装过docker，需要先删掉，之后再安装依赖:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo apt-get remove docker docker-engine docker.io
sudo apt-get install apt-transport-https ca-certificates curl gnupg2 software-properties-common
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>2、根据版本不同，运行公钥，添加软件仓库。</p><p>信任Docker的GPG公钥:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Debian
curl -fsSL https://repo.huaweicloud.com/docker-ce/linux/debian/gpg | sudo apt-key add -
# Ubuntu
curl -fsSL https://repo.huaweicloud.com/docker-ce/linux/ubuntu/gpg | sudo apt-key add -
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对于amd64架构的计算机，添加软件仓库:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Debian
sudo add-apt-repository &quot;deb [arch=amd64] https://repo.huaweicloud.com/docker-ce/linux/debian $(lsb_release -cs) stable&quot;
# Ubuntu
sudo add-apt-repository &quot;deb [arch=amd64] https://repo.huaweicloud.com/docker-ce/linux/ubuntu $(lsb_release -cs) stable&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对于树莓派或其它Arm架构计算机，请运行:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Debian
echo &quot;deb [arch=armhf] https://repo.huaweicloud.com/docker-ce/linux/debian $(lsb_release -cs) stable&quot; | sudo tee /etc/apt/sources.list.d/docker.list
# Ubuntu
echo &quot;deb [arch=armhf] https://repo.huaweicloud.com/docker-ce/linux/ubuntu $(lsb_release -cs) stable&quot; | sudo tee /etc/apt/sources.list.d/docker.list
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>3、更新索引文件并安装</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo apt-get update
sudo apt-get install docker-ce
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="阿里云镜像加速" tabindex="-1"><a class="header-anchor" href="#阿里云镜像加速" aria-hidden="true">#</a> 阿里云镜像加速</h3>`,49),x={href:"https://promotion.aliyun.com/ntms/act/kubernetes.html",target:"_blank",rel:"noopener noreferrer"},_=e("li",null,[e("p",null,"注册一个属于自己的阿里云账户")],-1),f=e("li",null,[e("p",null,"获得加速器地址连接："),e("ol",null,[e("li",null,"​登陆阿里云开发者平台"),e("li",null,"点击控制台"),e("li",null,"选择容器镜像服务"),e("li",null,"获取加速器地址")])],-1),D=r(`<p>粘贴脚本直接执行</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> /etc/docker 
<span class="token function">tee</span> /etc/docker/daemon.json <span class="token operator">&lt;&lt;-</span><span class="token string">&#39;EOF&#39;
{ 
  &quot;registry-mirrors&quot;: [&quot;https://aa25jngu.mirror.aliyuncs.com&quot;] 
} 
EOF</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>或者分开步骤执行</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>mkdir -p /etc/docker
vim /etc/docker/daemon.json
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>重启服务器</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 重启服务器</span>
systemctl daemon-reload
systemctl restart <span class="token function">docker</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="永远的helloworld" tabindex="-1"><a class="header-anchor" href="#永远的helloworld" aria-hidden="true">#</a> 永远的HelloWorld</h3><p>启动Docker后台容器（测试运行 hello-world）</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># 命令
docker run hello-world
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>​<img src="`+m+'" alt="24-20230617203109-ce0umeg" loading="lazy">​</p><h3 id="底层原理" tabindex="-1"><a class="header-anchor" href="#底层原理" aria-hidden="true">#</a> 底层原理</h3><p>为什么Docker会比VM虚拟机快:</p><ul><li><p>docker有着比虚拟机更少的抽象层</p><p>由于docker不需要Hypervisor(虚拟机)实现硬件资源虚拟化,运行在docker容器上的程序直接使用的都是实际物理机的硬件资源。因此在CPU、内存利用率上docker将会在效率上有明显优势。</p></li><li><p>docker利用的是宿主机的内核,而不需要加载操作系统OS内核</p><p>当新建一个容器时,docker不需要和虚拟机一样重新加载一个操作系统内核。进而避免引寻、加载操作系统内核返回等比较费时费资源的过程,当新建一个虚拟机时,虚拟机软件需要加载OS,返回新建过程是分钟级别的。而docker由于直接利用宿主机的操作系统,则省略了返回过程,因此新建一个docker容器只需要几秒钟。</p></li></ul><p>​<img src="'+h+'" alt="25-20230617203109-3itur2i" loading="lazy">​</p><p>‍</p>',15);function y(w,q){const n=s("ExternalLinkIcon");return o(),t("div",null,[b,e("p",null,[a("​最大的公开仓库是 Docker Hub("),e("a",g,[a("https://hub.docker.com/"),d(n)]),a(") ，存放了数量庞大的镜像供用户下载。")]),k,e("ul",null,[e("li",null,[e("p",null,[a("​地址："),e("a",x,[a("https://promotion.aliyun.com/ntms/act/kubernetes.html"),d(n)])])]),_,f]),D])}const C=i(v,[["render",y],["__file","Docker安装.html.vue"]]);export{C as default};
